import { useEffect, useState } from "react"

const mockData = [{
    "name": "root1",
    "type": "folder",
    "id": 1,
    "children": [
        {
            "name": "documents",
            "type": "folder",
            "id": 2,
            "children": [
                { "name": "resume.pdf", "id": 4, "type": "file", "size": "120KB" },
                { "name": "project.docx", "id": 5, "type": "file", "size": "500KB" }
            ]
        },
        {
            "name": "images",
            "type": "folder",
            "id": 3,
            "children": [
                { "name": "logo.png", "id": 6, "type": "file", "size": "50KB" }
            ]
        },
        { "name": "config.json", "id": 7, "type": "file", "size": "1KB" }
    ]
},
{
    "name": "root2",
    "type": "file",
    "id": 8,
},
{
    "name": "documents1",
    "type": "folder",
    "id": 14,
    "children": [
        { "name": "resume1.pdf", "id": 9, "type": "file", "size": "120KB" },
        { "name": "project1.docx", "id": 10, "type": "file", "size": "500KB" }
    ]
},
{
    "name": "images1",
    "type": "folder",
    "id": 13,
    "children": [
        { "name": "logo1.png", "id": 11, "type": "file", "size": "50KB" }
    ]
},
{ "name": "config1.json", "id": 12, "type": "file", "size": "1KB" }]

function useTreeData() {
    const [appData, setAppData] = useState({
        data: null,
        loading: false,
        error: null
    })

    function getData() {
        return new Promise((resolve) => {
            setTimeout(() => {
                resolve(mockData)
            }, 0)
        })
    }

    async function fetchData() {
        setAppData(prev => {
            return {
                ...prev,
                loading: true
            }
        })
        try {
            const data = await getData()
            console.log('>>>', data)
            setAppData(prev => {
                return {
                    ...prev,
                    data: data
                }
            })
        } catch (err) {
            setAppData(prev => {
                return {
                    ...prev,
                    error: err
                }
            })
        } finally {
            setAppData(prev => {
                return {
                    ...prev,
                    loading: false
                }
            })
        }
    }
    useEffect(() => {
        fetchData();
    }, [])

    return appData
}

export default useTreeData
